#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_TITLE_LEN 101

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        getchar(); // consume newline after N
        char **titles = (char **)malloc(N * sizeof(char *));
        for (int i = 0; i < N; ++i) {
            titles[i] = (char *)malloc(MAX_TITLE_LEN);
            if (!fgets(titles[i], MAX_TITLE_LEN, stdin)) titles[i][0] = '\0';
            titles[i][strcspn(titles[i], "\n")] = '\0';
        }
        // simple O(N^2) duplicate check – sufficient for given limits
        for (int i = 0; i < N; ++i) {
            int dup = 0;
            for (int j = 0; j < i; ++j) {
                if (strcmp(titles[i], titles[j]) == 0) { dup = 1; break; }
            }
            if (!dup) {
                printf("%s\n", titles[i]);
            }
        }
        for (int i = 0; i < N; ++i) free(titles[i]);
        free(titles);
    }
    return 0;
}

