#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin >> T)) return 0;
    while (T--) {
        int N; cin >> N; string line; getline(cin, line); // consume endline
        unordered_set<string> seen;
        for (int i = 0; i < N; ++i) {
            string title; getline(cin, title);
            if (seen.find(title) == seen.end()) {
                seen.insert(title);
                cout << title << '\n';
            }
        }
    }
    return 0;
}

