const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const T = parseInt(lines[idx++], 10);
let output = [];
for (let t = 0; t < T; ++t) {
  const N = parseInt(lines[idx++], 10);
  const seen = new Set();
  for (let i = 0; i < N; ++i) {
    const title = lines[idx++];
    if (!seen.has(title)) {
      seen.add(title);
      output.push(title);
    }
  }
}
